/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr1-#pr1-

statute 1 "Short title" effective 1872-01-01 {
    definitions {
        act_short_title := "This Act is the Penal Code 1871.";
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr10-#pr10-
statute 10 "“Man” and “woman”" effective 1872-01-01 {
    definitions {
        man := "The word “man” denotes a male human being of any age";
        woman := "“woman” denotes a female human being of any age";
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr100-#pr100-
/// @amendment [15/2019]

statute 100 "Right of private defence against deadly assault when there is risk of harm to innocent person" effective 1872-01-01 effective 2019-12-31 {
    definitions {
        right_of_private_defence_extends := "If, in the exercise of the right of private defence against an assault which causes the defender to reasonably believe that death would be caused to him or to any other person and the defender is so situated that he cannot effectually exercise that right without risk of harm to an innocent person, his right of private defence extends to the running of that risk. [15/2019]";
    }

    elements {
        /// Section 100 is conjunctive: the extension applies only when the defence is being exercised against a deadly assault and it cannot be effectually exercised without risking harm to an innocent person.
        all_of {
            circumstance exercise_of_right := "In the exercise of the right of private defence";
            circumstance assault_causing_reasonable_belief_of_death := "Against an assault which causes the defender to reasonably believe that death would be caused to him or to any other person";
            circumstance cannot_effectually_exercise_without_risk := "The defender is so situated that he cannot effectually exercise that right without risk of harm to an innocent person";
            circumstance extension_to_running_risk := "His right of private defence extends to the running of that risk";
        }
    }

    /// Illustration
    illustration illustration {
        "A is attacked by a mob who attempt to murder him. A cannot effectually exercise his right of private defence without firing on the mob, and he cannot fire without risk of harming young children who are mingled with the mob. A commits no offence if by so firing he harms any of the children."
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr101-#pr101-
/// @amendment [15/2019]

statute 101 "Start and continuance of right of private defence of body" effective 1872-01-01 effective 2020-01-01 {
    subsection (1) {
        definitions {
            commencement_rule := "The right of private defence of the body starts as soon as the defender reasonably believes that there is danger to the body (either his own or that of any other person) arising from any act which is an offence against the human body or an attempt or a threat to commit the offence, though the offence may not have been committed. [15/2019]";
        }
    }

    subsection (2) {
        definitions {
            continuance_rule := "The right of private defence continues as long as the belief of danger mentioned in subsection (1) continues. [15/2019]";
        }
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr102-#pr102-
/// @amendment [Act 23 of 2021 wef 01/03/2022]
/// @amendment [15/2019]

statute 102 "When right of private defence of body extends to causing death" effective 1872-01-01 effective 2019-12-31 effective 2022-03-01 {
    definitions {
        operative_rule := "The right of private defence of the body extends, under the restrictions mentioned in sections 98 and 106A, to the voluntary causing of death to the assailant, if the offence which gives rise to the exercise of the right is of any of the following descriptions:";
    }

    elements {
        all_of {
            actus_reus causing_death_to_assailant := "The voluntary causing of death to the assailant";
            circumstance right_of_private_defence_of_body := "The right of private defence of the body is being exercised";
            circumstance restrictions_in_sections_98_and_106A := "The exercise of the right is under the restrictions mentioned in sections 98 and 106A";
            /// the triggering offence may be any one of the six statutory descriptions
            any_of {
                circumstance assault_with_apprehended_death := "An assault where the defender reasonably believes that death will otherwise be the consequence of such assault";
                circumstance assault_with_apprehended_grievous_hurt := "An assault where the defender reasonably believes that grievous hurt will otherwise be the consequence of such assault";
                circumstance assault_with_intention_of_committing_rape := "An assault that the defender reasonably believes to be done with the intention of committing rape as described in section 375 or causing such rape to be committed";
                circumstance assault_with_intention_of_penile_penetration := "An assault that the defender reasonably believes to be done with the intention of causing penile penetration of the vagina, anus or mouth as described in section 376(2)";
                circumstance assault_with_intention_of_kidnapping_or_abducting := "An assault that the defender reasonably believes to be done with the intention of kidnapping or abducting";
                circumstance assault_with_intention_of_wrongful_confinement := "An assault that the defender reasonably believes to be done with the intention of wrongfully confining a person, under circumstances which may reasonably cause him to believe that he will be unable to have opportunity for recourse to a public authority for his release";
            }
        }
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr103-#pr103-
/// @amendment [15/2019]
statute 103 "When such right extends to causing any harm other than death" effective 1872-01-01 effective 2019-12-31 {
    definitions {
        scope_of_nonfatal_private_defence := "If the offence is not of any of the descriptions mentioned in section 102, the right of private defence of the body does not extend to the voluntary causing of death to the assailant, but does extend, under the restrictions mentioned in sections 98 and 106A, to the voluntary causing to the assailant of any harm other than death. [15/2019]";
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr104-#pr104-
/// @amendment [15/2019]

statute 104 "Commencement and continuance of right of private defence of property" effective 1872-01-01 effective 2019-12-31 {
    subsection (1) {
        definitions {
            commencement_of_right := "The right of private defence of property starts when the defender reasonably believes that there was a danger to property (either his own or that of any other person) arising from any act which is an offence falling under the definition of theft, robbery, mischief or criminal trespass, or which is an attempt to commit such an offence. [15/2019]";
        }
    }

    subsection (2) {
        definitions {
            continuance_against_theft := "The right of private defence of property against theft continues till — [15/2019]";
        }

        subsection (a) {
            definitions {
                theft_continuance_until_retreat := "the offender has effected his retreat with the property;";
            }
        }

        subsection (b) {
            definitions {
                theft_continuance_until_public_authority_assistance := "the assistance of a public authority is obtained; or";
            }
        }

        subsection (c) {
            definitions {
                theft_continuance_until_recovery := "the property has been recovered.";
            }
        }
    }

    subsection (3) {
        definitions {
            continuance_against_robbery := "The right of private defence of property against robbery continues as long as the offender causes or attempts to cause to any person death or hurt or wrongful restraint, or as long as the fear of instant death or of instant hurt or of instant personal restraint continues. [15/2019]";
        }
    }

    subsection (4) {
        definitions {
            continuance_against_criminal_trespass_or_mischief := "The right of private defence of property against criminal trespass or mischief continues as long as the offender continues in the commission of criminal trespass or mischief. [15/2019]";
        }
    }

    subsection (5) {
        definitions {
            continuance_against_house_breaking := "The right of private defence of property against house-breaking continues as long as such house-breaking continues. [15/2019]";
        }
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr105-#pr105-
/// @amendment [15/2019]

statute 105 "When right of private defence of property extends to causing death" effective 1872-01-01 effective 2020-01-01 {
    subsection (1) {
        elements {
            /// subsection (1) extends the right only where the baseline right, restrictions, belief, and one listed danger-description all coexist.
            all_of {
                permission right_extends := "The right of private defence of property extends, under the restrictions mentioned in sections 98 and 106A, to the voluntary causing of death to the wrongdoer";
                circumstance reasonable_belief_of_danger := "The defender reasonably believes that there was a danger to property (either his own or that of any other person)";
                circumstance listed_description := "The danger to property arose from any of the following descriptions";
                any_of {
                    circumstance robbery := "robbery";
                    all_of {
                        circumstance house_breaking_night := "house-breaking committed after 7 p.m. and before 7 a.m. and if the wrongdoer —";
                        any_of {
                            circumstance effects_entrance_in_six_ways := "effects his entrance into the house or any part of it in any of the 6 ways described in subsection (2); or";
                            circumstance leaves_in_six_ways_after_offence := "being in the house or any part of it for the purpose of committing an offence, or having committed an offence therein, the wrongdoer leaves the house or any part of it in any of these 6 ways;";
                        }
                    }
                    circumstance mischief_by_fire := "mischief by fire committed on any building, tent, container or vessel, which building, tent, container or vessel is used as a human dwelling, or as a place for the custody of property";
                    circumstance theft_mischief_or_house_breaking_with_further_risk := "theft, mischief or house-breaking, under such circumstances where the defender reasonably believes that death or grievous hurt will be the consequence, if such right of private defence is not exercised";
                }
            }
        }
    }

    subsection (2) {
        definitions {
            six_ways_of_entry_or_leaving := "For the purposes of subsection (1)( b ), the 6 ways of entry or leaving by a wrongdoer are as follows:";
        }

        elements {
            any_of {
                circumstance way_a := "if the wrongdoer enters or leaves through a passage made by the wrongdoer, or by any abettor of the house-breaking in order to commit the house‑breaking;";
                circumstance way_b := "if the wrongdoer enters or leaves through any passage not intended by any person, other than the wrongdoer or an abettor of the offence, for human entrance, or through any passage to which the wrongdoer has obtained access by scaling or climbing over any wall or building;";
                circumstance way_c := "if the wrongdoer enters or leaves through any passage which the wrongdoer or any abettor of the house-breaking has opened, in order to commit the house‑breaking, by any means by which that passage was not intended by the occupier of the house to be opened;";
                circumstance way_d := "if the wrongdoer enters or leaves by opening any lock in order to commit the house-breaking, or in order to leave from the house after a house-breaking;";
                circumstance way_e := "if the wrongdoer effects his entry or leaving by using criminal force or committing an assault, or by threatening any person with assault;";
                circumstance way_f := "if the wrongdoer enters or leaves by any passage which he knows to have been fastened against such entry or leaving, and to have been unfastened by himself or by an abettor of the house-breaking.";
            }
        }
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr106-#pr106-
/// @amendment [15/2019]

statute 106 "When such right extends to causing any harm other than death" effective 1872-01-01 effective 2020-01-01 {
    definitions {
        scope_of_nonfatal_private_defence_of_property := "If the offence, the committing or the attempt to commit of which occasions the exercise of the right of private defence, is theft, mischief, or criminal trespass, not of any of the descriptions mentioned in section 105, that right does not extend to the voluntary causing of death, but does extend, subject to the restrictions mentioned in sections 98 and 106A, to the voluntary causing to the wrongdoer of any harm other than death. [15/2019]";
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr106A-#pr106A-
/// @amendment [15/2019]

statute 106A "Acts against which there is no right of private defence" effective 1872-01-01 effective 2019-12-31 {
    subsection (1) {
        definitions {
            no_right_against_public_servant_act := "There is no right of private defence against an act which does not cause the defender to reasonably believe that death or grievous hurt would result, if done, or attempted to be done, by a public servant acting in good faith under the actual or apparent authority of his office, though that act may not be strictly justifiable by law. [15/2019]";
            explanation_1 := "Explanation 1.—A person is not deprived of the right of private defence against an act done, or attempted to be done, by a public servant, as such, unless he knows, or has reason to believe, that the person doing the act is such public servant.";
        }

        elements {
            /// Subsection (1) is conjunctive: the right is excluded only when the act, belief threshold, and public-servant authority conditions are all present.
            all_of {
                actus_reus act_done_or_attempted := "An act is done, or attempted to be done";
                circumstance no_reasonable_belief_of_death_or_grievous_hurt := "The act does not cause the defender to reasonably believe that death or grievous hurt would result";
                circumstance public_servant_status := "The act is done, or attempted to be done, by a public servant";
                mens_rea good_faith := "The public servant is acting in good faith";
                circumstance actual_or_apparent_authority := "The public servant is acting under the actual or apparent authority of his office";
                circumstance knowledge_of_public_servant_status := "The person deprived of the right of private defence knows, or has reason to believe, that the person doing the act is such public servant";
            }
        }
    }

    subsection (2) {
        definitions {
            no_right_against_act_under_public_servant_direction := "There is no right of private defence against an act which does not cause the defender to reasonably believe that death or grievous hurt would result, if done, or attempted to be done, by the direction of a public servant acting in good faith under the actual or apparent authority of the public servant’s office, though that direction may not be strictly justifiable by law. [15/2019]";
            explanation_2 := "Explanation 2.—A person ( A ) is not deprived of the right of private defence against an act done, or attempted to be done, by the direction of a public servant, unless A knows, or has reason to believe, that the person doing the act ( B ) is acting by such direction; or unless B states the authority under which B acts, or, if B has authority in writing, unless B produces such authority, if demanded.";
        }

        elements {
            /// Subsection (2) is conjunctive, subject to the Explanation 2 alternatives on notice of the public servant's direction.
            all_of {
                actus_reus act_done_or_attempted := "An act is done, or attempted to be done";
                circumstance no_reasonable_belief_of_death_or_grievous_hurt := "The act does not cause the defender to reasonably believe that death or grievous hurt would result";
                actus_reus acted_by_direction := "The act is done, or attempted to be done, by the direction of a public servant";
                mens_rea good_faith := "The public servant is acting in good faith";
                circumstance actual_or_apparent_authority := "The public servant is acting under the actual or apparent authority of the public servant’s office";
                any_of {
                    circumstance knowledge_of_direction := "A knows, or has reason to believe, that B is acting by such direction";
                    actus_reus authority_stated := "B states the authority under which B acts";
                    all_of {
                        circumstance written_authority := "B has authority in writing";
                        actus_reus written_authority_produced_if_demanded := "B produces such authority, if demanded";
                    }
                }
            }
        }
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr107-#pr107-
/// @amendment [15/2019]

statute 107 "Abetment of the doing of a thing" effective 1872-01-01 effective 2020-01-01 {
    subsection (1) {
        definitions {
            explanation_1_instigation := "Explanation 1.—A person who, by intentional misrepresentation, or by intentional concealment of a material fact which he is bound to disclose, voluntarily causes or procures, or attempts to cause or procure, a thing to be done, is said to instigate the doing of that thing.";
            explanation_2_aid := "Explanation 2.—Whoever, either prior to or at the time of the commission of an act, does anything in order to facilitate the commission of that act, and thereby facilitates the commission thereof, is said to aid the doing of that act.";
        }

        elements {
            /// Subsection (1) is disjunctive: any one of the three statutory limbs is sufficient for abetment.
            any_of {
                actus_reus instigation := "Instigates any person to do that thing";
                all_of {
                    actus_reus conspiracy := "Engages with one or more other person or persons in any conspiracy for the doing of that thing";
                    circumstance act_or_illegal_omission_in_pursuance := "An act or illegal omission takes place in pursuance of that conspiracy";
                    circumstance in_order_to_do_thing := "That act or illegal omission is in order to the doing of that thing";
                }
                actus_reus intentional_aid := "Intentionally aids, by any act or illegal omission, the doing of that thing";
            }
        }
    }

    subsection (2) {
        definitions {
            impossibility_not_a_bar := "A person may abet the doing of a thing despite the existence of facts of which he is unaware which make the doing of the thing impossible. [15/2019]";
        }
    }

    illustration illustration {
        "A , a public officer, is authorised by a warrant from a court of justice to apprehend Z . B , knowing that fact and also that C is not Z , intentionally represents to A that C is Z , and thereby intentionally causes A to apprehend C . Here B abets by instigation the apprehension of C ."
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr108-#pr108-

statute 108 "Abettor" effective 1872-01-01 {
    definitions {
        abettor := "A person abets an offence who abets either the commission of an offence, or the commission of an act which would be an offence, if committed by a person capable by law of committing an offence with the same intention or knowledge as that of the abettor.";
        act_which_would_be_offence := "An act which would be an offence, if committed by a person capable by law of committing an offence with the same intention or knowledge as that of the abettor.";
        explanation_1 := "Explanation 1.—The abetment of the illegal omission of an act may amount to an offence, although the abettor may not himself be bound to do that act.";
        explanation_2 := "Explanation 2.—To constitute the offence of abetment, it is not necessary that the act abetted should be committed, or that the effect requisite to constitute the offence should be caused.";
        explanation_3 := "Explanation 3.—It is not necessary that the person abetted should be capable by law of committing an offence, or that he should have the same guilty intention or knowledge as that of the abettor, or any guilty intention or knowledge.";
        explanation_4 := "Explanation 4.—The abetment of an offence being an offence, the abetment of such an abetment is also an offence.";
        explanation_5 := "Explanation 5.—It is not necessary to the commission of the offence of abetment by conspiracy that the abettor should concert the offence with the person who commits it. It is sufficient if he engages in the conspiracy in pursuance of which the offence is committed.";
    }

    /// Illustrations
    illustration illustration_a {
        "( a ) A instigates B to murder C . B refuses to do so. A is guilty of abetting B to commit murder."
    }

    illustration illustration_b {
        "( b ) A instigates B to murder D . B , in pursuance of the instigation, stabs D . D recovers from the wound. A is guilty of instigating B to commit murder."
    }

    /// Illustrations
    illustration illustration_c {
        "( a ) A , with a guilty intention, abets a child or a person of unsound mind to commit an act which would be an offence if committed by a person capable by law of committing an offence, and having the same intention as A . Here A , whether the act is committed or not, is guilty of abetting an offence."
    }

    illustration illustration_d {
        "( b ) A , with the intention of murdering Z , instigates B , a child below 7 years of age, to do an act which causes Z ’s death. B , in consequence of the abetment, does the act, and thereby causes Z ’s death. Here, though B was not capable by law of committing an offence, A is liable to be punished in the same manner as if B had been capable by law of committing an offence and had committed murder, and he is therefore subject to the punishment of death."
    }

    illustration illustration_e {
        "( c ) A instigates B to set fire to a dwelling house. B , in consequence of the unsoundness of his mind, being incapable of knowing the nature of the act, or that he is doing what is wrong or contrary to law, sets fire to the house in consequence of A ’s instigation. B has committed no offence, but A is guilty of abetting the offence of setting fire to a dwelling house, and is liable to the punishment provided for that offence."
    }

    illustration illustration_f {
        "( d ) A , intending to cause a theft to be committed, instigates B to take property belonging to Z out of Z ’s possession. A induces B to believe that the property belongs to A . B takes the property out of Z ’s possession, in good faith believing it to be A ’s property. B , acting under this misconception, does not take dishonestly, and therefore does not commit theft. But A is guilty of abetting theft, and is liable to the same punishment as if B had committed theft."
    }

    /// Illustration
    illustration illustration_g {
        "A instigates B to instigate C to murder Z . B accordingly instigates C to murder Z , and C commits that offence in consequence of B ’s instigation. B is liable to be punished for his offence with the punishment for murder; and as A instigated B to commit the offence A is also liable to the same punishment."
    }

    /// Illustration
    illustration illustration_h {
        "A concerts with B a plan for poisoning Z . It is agreed that A shall administer the poison. B then explains the plan to C , mentioning that a third person is to administer the poison, but without mentioning A ’s name. C agrees to procure the poison, and procures and delivers it to B for the purpose of its being used in the manner explained. A administers the poison; Z dies in consequence. Here, though A and C have not conspired together, yet C has been engaged in the conspiracy in pursuance of which Z has been murdered. C has therefore committed the offence defined in this section, and is liable to the punishment for murder."
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr108A-#pr108A-

statute 108A "Abetment in Singapore of an offence outside Singapore" effective 1872-01-01 {
    elements {
        all_of {
            actus_reus abetment_in_singapore := "In Singapore, abets the commission of any act without and beyond Singapore";
            circumstance singapore_offence_equivalence := "That act would constitute an offence if committed in Singapore";
        }
    }

    illustration example1 {
        "A , in Singapore, instigates B , a foreigner in Java, to commit murder in Java. A is guilty of abetting murder."
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr108B-#pr108B-

statute 108B "Abetment outside Singapore of an offence in Singapore" effective 1872-01-01 effective 2008-02-01 {
    elements {
        all_of {
            actus_reus abets_offence_in_singapore := "Abets an offence committed in Singapore";
            circumstance abetment_acts_done_outside_singapore := "Any or all of the acts constituting the abetment were done outside Singapore";
        }
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr109-#pr109-

statute 109 "Punishment of abetment if the act abetted is committed in consequence, and where no express provision is made for its punishment" effective 1872-01-01 {
    definitions {
        explanation_in_consequence_of_abetment := "Explanation .—An act or offence is said to be committed in consequence of abetment, when it is committed in consequence of the instigation, or in pursuance of the conspiracy, or with the aid which constitutes the abetment."
    }

    elements {
        /// This section applies only when all three statutory conditions are satisfied.
        all_of {
            actus_reus abets_offence := "Abets any offence";
            circumstance act_abetted_committed_in_consequence := "The act abetted is committed in consequence of the abetment";
            circumstance no_express_provision_for_punishment := "No express provision is made by this Code for the punishment of such abetment";
        }
    }

    /// Punishment follows the punishment provided for the abetted offence.
    penalty {
        supplementary := "Whoever abets any offence shall, if the act abetted is committed in consequence of the abetment, and no express provision is made by this Code for the punishment of such abetment, be punished with the punishment provided for the offence."
    }

    /// Illustrations
    illustration illustration_a {
        "( a ) A offers a bribe to B , a public servant, as a reward for showing A some favour in the exercise of B ’s official functions. B accepts the bribe. A has abetted the offence defined in section 161."
    }

    illustration illustration_b {
        "( b ) A instigates B to give false evidence. B , in consequence of the instigation, commits that offence. A is guilty of abetting that offence, and is liable to the same punishment as B ."
    }

    illustration illustration_c {
        "( c ) A and B conspire to poison Z . A , in pursuance of the conspiracy, procures the poison and delivers it to B , in order that he may administer it to Z . B , in pursuance of the conspiracy, administers the poison to Z , in A ’s absence and thereby causes Z ’s death. Here B is guilty of murder. A is guilty of abetting that offence by conspiracy, and is liable to the punishment for murder."
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr11-#pr11-
// Singapore Penal Code Section 11 - "Person"
// Shape: interpretation / definition

statute 11 "Person" effective 1872-01-01 {
    definitions {
        person := "Any company or association or body of persons, whether incorporated or not";
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr110-#pr110-

statute 110 "Punishment of abetment if the person abetted does the act with a different intention from that of the abettor" effective 1872-01-01 {
    elements {
        all_of {
            actus_reus abets_commission_of_offence := "Whoever abets the commission of an offence";
            circumstance person_abetted_does_act := "the person abetted does the act";
            circumstance different_intention_or_knowledge := "with a different intention or knowledge from that of the abettor";
        }
    }

    /// punishment provision keyed to the counterfactual offence that would have been committed with the abettor's intention or knowledge
    penalty {
        supplementary := "be punished with the punishment provided for the offence which would have been committed if the act had been done with the intention or knowledge of the abettor and with no other.";
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr111-#pr111-

statute 111 "Liability of abettor when one act is abetted and a different act is done" effective 1872-01-01 {
    elements {
        all_of {
