/// @amendment [15/2019]

statute 212 "Harbouring an offender" effective 1872-01-01 effective 2019-12-31 {
    subsection (1) {
        elements {
            /// Liability under subsection (1) requires a completed offence, harbouring or concealment, knowledge or reason to believe, screening intent, and one punishment tier for the predicate offence.
            all_of {
                circumstance offence_committed := "Whenever an offence has been committed";
                actus_reus harbours_or_conceals := "Harbours or conceals a person";
                mens_rea knowledge_of_offender := "Knows or has reason to believe to be the offender";
                mens_rea intention_to_screen := "With the intention of screening him from legal punishment";
                any_of {
                    circumstance death_punishable_offence := "The offence is punishable with death";
                    circumstance life_or_20_year_offence := "The offence is punishable with imprisonment for life, or with imprisonment which may extend to 20 years";
                    circumstance one_year_and_not_20_year_offence := "The offence is punishable with imprisonment which may extend to one year and not to 20 years";
                }
            }
        }

        penalty when death_punishable_offence {
            imprisonment := 0 years .. 10 years;
            fine := unlimited;
        }

        penalty when life_or_20_year_offence {
            imprisonment := 0 years .. 7 years;
            fine := unlimited;
        }

        penalty or_both when one_year_and_not_20_year_offence {
            fine := unlimited;
            supplementary := "Shall be punished with imprisonment for a term which may extend to one‑fourth part of the longest term of imprisonment provided for that offence, or with fine, or with both.";
        }

        illustration illustration_a {
            "( a ) A , knowing that B has committed gang‑robbery, knowingly conceals B in order to screen him from legal punishment. Here, as B is liable to imprisonment for a term of not less than 5 years and not more than 20 years, A is liable to imprisonment for a term not exceeding 7 years, and is also liable to fine."
        }

        illustration illustration_b {
            "( b ) A and B are married to each other, and live in their matrimonial home. A knows that B has committed house‑breaking. A provides food and shelter to B , with no intention to screen B from legal punishment. A is not guilty of the offence of harbouring."
        }

        illustration illustration_c {
            "( c ) A and B are married to each other, and live in their matrimonial home. A knows that B has committed gang‑robbery and is preparing to leave Singapore to evade arrest. A provides food and shelter to B for the purposes of helping B evade detection by the police before he leaves Singapore. A is guilty of the offence of harbouring."
        }
    }

    subsection (2) {
        definitions {
            offence := "Includes any act committed at any place out of Singapore which if committed in Singapore would be punishable under any of the following sections, namely, 302, 304, 382, 392, 393, 394, 395, 396, 397, 399, 402, 435, 436, 449, 450, 459 and 460";
