        }
    }

    subsection (3) {
        definitions {
            application_subsection_3 := "In sections 375 to 377BO —";
            penetration_continuing_act := "(a) penetration is a continuing act from entry to withdrawal;";
            reference_to_part_of_body_includes_surgically_constructed_part := "(b) a reference to a part of the body includes a reference to a part which is surgically constructed (in particular, through a sex reassignment procedure);";
            identifying_sex_of_person := "(c) for the purposes of identifying the sex of a person —";
            identifying_sex_identity_card := "(i) the sex of a person as stated in that person’s identity card issued under the National Registration Act 1965 at the time the sexual activity took place is prima facie evidence of the sex of that person; and";
            identifying_sex_reassignment := "(ii) a person who has undergone a sex reassignment procedure is identified as being of the sex to which that person has been reassigned;";
            meaning_of_sexual := "(d) penetration, touching, communication or other activity is “sexual” if —";
            sexual_because_of_nature := "(i) because of its nature it is sexual, whatever its circumstances or any person’s purpose in relation to it may be; or";
            sexual_because_of_nature_and_circumstances_or_purpose := "(ii) because of its nature it may be sexual and because of its circumstances or the purpose of any person in relation to it (or both) it is sexual;";
            references_to_observation := "(e) references to observation (however expressed) are to observation whether direct or by looking at an image;";
            private_act_definition := "(f) a person is doing a private act if under circumstances in which the person has a reasonable expectation of privacy, the person —";
            private_act_exposed_genital_region_buttocks_or_breasts := "(i) is in a state where the person’s genital region, buttocks or breasts (if the person is a female) are exposed or covered only in underwear;";
            private_act_using_toilet_showering_or_bathing := "(ii) is using a toilet, showering or bathing; or";
            private_act_sexual_act_not_ordinarily_done_in_public := "(iii) is doing a sexual act that is not of a kind ordinarily done in public.";
        }

        illustration illustration {
            "A is showering in an open-concept shower cubicle at the changing room of a swimming pool and cannot reasonably expect not to be casually observed. However, A has a reasonable expectation that A will not be surreptitiously recorded by a video camera."
