/// @amendment [15/2019]

statute 377CA "Meaning of exploitative relationship" effective 1872-01-01 effective 2020-01-01 {
    subsection (1) {
        elements {
            circumstance exploitative_relationship_determination := "For the purposes of sections 375, 376, 376A, 376AA, 376EA, 376EC, 376EE, 377BL and 377D, whether an accused person’s relationship with a person below 18 years of age (called in this section a minor) is exploitative of the minor is to be determined by the court in the circumstances of each case and the court must have regard to the following in making such determination:";
            all_of {
                circumstance determination_factor_age_of_minor := "the age of the minor;";
                circumstance determination_factor_age_difference := "the difference between the age of the accused person and the minor;";
                circumstance determination_factor_nature_of_relationship := "the nature of the relationship;";
                circumstance determination_factor_degree_of_control_or_influence := "the degree of control or influence exercised by the accused person over the minor. [15/2019]";
            }
        }
    }

    subsection (2) {
        elements {
            circumstance rebuttable_presumption_exploitative_relationship := "For the purposes of subsection (1) and subject to subsection (3), it is presumed until the contrary is proved that an accused person’s relationship with a minor is exploitative where the relationship is any of the following:";
            any_of {
                circumstance accused_parent_step_parent_guardian_or_foster_parent := "the accused person is the parent, step‑parent, guardian or foster parent of the minor;";
                circumstance accused_de_facto_partner_of_parent_guardian_or_foster_parent := "the accused person is the de facto partner of the parent, guardian or foster parent of the minor;";
                circumstance accused_teaching_or_management_staff := "the accused person is a member of the teaching or management staff of the school or educational institution at which the minor is a student;";
                circumstance accused_personal_relationship_instruction := "the accused person has an established personal relationship with the minor in connection with the provision of religious, sporting, musical or other instruction to the minor;";
                circumstance accused_custodial_officer := "the accused person is a custodial officer of an institution in which the minor is detained;";
                circumstance accused_practitioner_or_psychologist_patient_relationship := "the accused person is a registered medical practitioner, a registered traditional Chinese medicine practitioner or a psychologist and the minor is a patient of the accused person;";
                circumstance accused_advocate_solicitor_or_counsellor_client_relationship := "the accused person is an advocate and solicitor or a counsellor and the minor is a client of the accused person.";
            }
        }
    }

    subsection (3) {
        definitions {
            lawful_marriage_exception_to_presumption := "The presumption in subsection (2) does not apply to a person who is lawfully married to a minor even though the relationship may fall within any of the relationships mentioned in subsection (2). [15/2019]";
        }
    }
}

