statute 378 "Theft" effective 1872-01-01 {
    definitions {
        theft := "Dishonestly taking movable property out of possession of another without consent";
        movable_property := "Corporeal property except land and things attached to earth";
        /// as defined in s24 of the Penal Code
        dishonestly := "With intention of causing wrongful gain or wrongful loss";
        wrongful_gain := "Gain by unlawful means of property to which the gainer is not legally entitled";
        wrongful_loss := "Loss by unlawful means of property to which the loser is legally entitled";
    }

