        element intention
    }

    caselaw "Chia Kok Weng v PP" "[1999] 2 SLR 1" {
        "Any moving of the property, however slight, constitutes the taking required for theft"
        element movement
    }

    illustration example1 {
        "A finds a watch on the road, not knowing to whom it belongs. A picks it up with intent to find the owner. A has not committed theft."
    }

    illustration example2 {
