        }
    }

    exception adult_consent_to_non_fatal_non_grievous_harm {
        "Nothing, which is not intended to cause death or grievous hurt, and which is not known by the doer to be likely to cause death or grievous hurt, is an offence by reason of any harm which it may cause, or be intended by the doer to cause, to any person above 18 years of age, who has given consent, whether express or implied, to suffer that harm; or by reason of any harm which it may be known by the doer to be likely to cause to any such person who has consented to take the risk of that harm."
        "Not an offence by reason of that harm"
    }

    illustration illustration {
        "A and Z agree to fence with each other for amusement. This agreement implies the consent of each to suffer any harm which, in the course of such fencing, may be caused without foul play; and if A , while playing fairly, hurts Z , A commits no offence."
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr88-#pr88-

statute 88 "Act not intended to cause death done by consent in good faith for the benefit of a person" effective 1872-01-01 {
    definitions {
        no_offence_rule := "Nothing, which is not intended to cause death, is an offence by reason of any harm which it may cause, or be intended by the doer to cause, or be known by the doer to be likely to cause, to any person for whose benefit it is done in good faith, and who has given a consent, whether express or implied, to suffer that harm, or to take the risk of that harm.";
        express_consent := "Consent given expressly to suffer the harm, or to take the risk of that harm.";
        implied_consent := "Consent impliedly given to suffer the harm, or to take the risk of that harm.";
    }

    elements {
        /// The section is conjunctive: the act is excused only where the act is not intended to cause death, is done for the person's benefit in good faith, and that person has consented to the harm or risk.
        all_of {
            actus_reus qualifying_act := "Thing done by the doer.";
            mens_rea no_intention_to_cause_death := "Act is not intended to cause death.";
            any_of {
                circumstance harm_caused := "Harm which the act may cause.";
                mens_rea harm_intended := "Harm intended by the doer to be caused.";
                mens_rea harm_known_likely := "Harm known by the doer to be likely to be caused.";
            }
            circumstance benefit := "Act is done to a person for whose benefit it is done.";
            mens_rea good_faith := "Act is done in good faith.";
            any_of {
                circumstance express_consent_given := "Person has given express consent to suffer that harm, or to take the risk of that harm.";
                circumstance implied_consent_given := "Person has given implied consent to suffer that harm, or to take the risk of that harm.";
            }
        }
    }

    exception consent_good_faith_benefit {
        "Nothing, which is not intended to cause death, is an offence by reason of any harm which it may cause, or be intended by the doer to cause, or be known by the doer to be likely to cause, to any person for whose benefit it is done in good faith, and who has given a consent, whether express or implied, to suffer that harm, or to take the risk of that harm."
        "No offence by reason of that harm."
    }

    illustration illustration_1 {
        "A , a surgeon, knowing that a particular operation is likely to cause the death of Z , who suffers under a painful complaint, but not intending to cause Z ’s death, and intending, in good faith, Z ’s benefit, performs that operation on Z , with Z ’s consent. A has committed no offence."
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr89-#pr89-

statute 89 "Act done in good faith for the benefit of a child or person of unsound mind, by or by consent of guardian" effective 1872-01-01 {
    definitions {
        no_offence_rule := "Nothing, which is done in good faith for the benefit of a person below 12 years of age, or of unsound mind, by or by consent, either express or implied, of the guardian or other person having lawful charge of that person, is an offence by reason of any harm which it may cause, or be intended by the doer to cause, or be known by the doer to be likely to cause, to that person:";
        express_consent := "Consent given expressly by the guardian or other person having lawful charge of the person.";
        implied_consent := "Consent impliedly given by the guardian or other person having lawful charge of the person.";
    }

    elements {
        /// The exception is conjunctive: the act must be done in good faith, for the protected person's benefit, and by or with qualifying guardian consent; the harm limb is disjunctive.
        all_of {
            actus_reus qualifying_act := "Thing done.";
            mens_rea good_faith := "Thing is done in good faith.";
            circumstance benefit := "Thing is done for the benefit of a person below 12 years of age, or of unsound mind.";
            any_of {
                actus_reus by_guardian_or_lawful_charge := "Thing is done by the guardian or other person having lawful charge of that person.";
                circumstance express_guardian_consent := "Thing is done by express consent of the guardian or other person having lawful charge of that person.";
                circumstance implied_guardian_consent := "Thing is done by implied consent of the guardian or other person having lawful charge of that person.";
            }
            any_of {
                circumstance harm_caused := "Harm which the thing may cause to that person.";
                mens_rea harm_intended := "Harm intended by the doer to be caused to that person.";
                mens_rea harm_known_likely := "Harm known by the doer to be likely to be caused to that person.";
            }
        }
    }

    exception guardian_good_faith_benefit {
        "Nothing, which is done in good faith for the benefit of a person below 12 years of age, or of unsound mind, by or by consent, either express or implied, of the guardian or other person having lawful charge of that person, is an offence by reason of any harm which it may cause, or be intended by the doer to cause, or be known by the doer to be likely to cause, to that person:"
        "No offence by reason of that harm."
    }

    illustration illustration_1 {
        "A , in good faith, for the benefit of his child, being below 12 years of age, without his child’s consent, has his child cut for the stone by a surgeon, knowing it to be likely that the operation will cause the child’s death, but not intending to cause the child’s death. A is within the exception, inasmuch as his object was the cure of the child."
    }
}

