/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr91-#pr91-
statute 91 "Acts which are offences independently of harm caused to the person consenting, are not within the exceptions in sections 87, 88 and 89" effective 1872-01-01 {
    definitions {
        consent_exception_limitation := "The exceptions in sections 87, 88 and 89 do not extend to acts which are offences independently of any harm which they may cause, or be intended to cause, or be known to be likely to cause, to the person giving the consent, or on whose behalf the consent is given.";
    }

    /// Illustration
    illustration illustration {
        "Causing miscarriage, unless it is authorised under the Termination of Pregnancy Act 1974 is an offence independently of any harm which it may cause or be intended to cause to the woman. Therefore it is not an offence “by reason of such harm”; and the consent of the woman, or of her guardian, to the causing of such miscarriage does not justify the act."
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr92-#pr92-
/// @amendment [ Deleted by Act 51 of 2007 ]

statute 92 "Act done in good faith for the benefit of a person without consent" effective 1872-01-01 {
    definitions {
        no_offence_rule := "Nothing is an offence by reason of any harm which it may cause to a person for whose benefit it is done in good faith, even without that person’s consent, if the circumstances are such that it is impossible for that person to signify consent, or if that person is incapable of giving consent, and has no guardian or other person in lawful charge of him from whom it is possible to obtain consent in time for the thing to be done with benefit:";
        pecuniary_benefit_excluded := "Explanation .—Mere pecuniary benefit is not benefit within the meaning of sections 88, 89 and 92.";
    }

    elements {
        /// The exception applies only where the act is done in good faith for the person's benefit and consent cannot be obtained in time because it cannot be signified or there is no available lawful guardian.
        all_of {
            actus_reus qualifying_act := "Thing done which may cause harm to a person.";
            circumstance beneficiary := "Act is done to a person for whose benefit it is done.";
            mens_rea good_faith := "Act is done in good faith.";
            circumstance without_consent := "Act is done even without that person’s consent.";
            any_of {
                circumstance impossible_to_signify_consent := "Circumstances are such that it is impossible for that person to signify consent.";
                all_of {
                    circumstance incapable_of_giving_consent := "That person is incapable of giving consent.";
                    circumstance no_guardian_or_lawful_charge_available := "That person has no guardian or other person in lawful charge of him from whom it is possible to obtain consent in time for the thing to be done with benefit.";
                }
            }
        }
    }

    exception good_faith_benefit_without_consent {
        "Nothing is an offence by reason of any harm which it may cause to a person for whose benefit it is done in good faith, even without that person’s consent, if the circumstances are such that it is impossible for that person to signify consent, or if that person is incapable of giving consent, and has no guardian or other person in lawful charge of him from whom it is possible to obtain consent in time for the thing to be done with benefit:"
        "No offence by reason of that harm."
    }

    /// Illustrations
    illustration illustration_a {
        "( a ) Z is thrown from his horse, and is insensible. A , a surgeon, finds that Z requires to be trepanned. A , not intending Z ’s death, but in good faith, for Z ’s benefit, performs the trepan before Z recovers his power of judging for himself. A has committed no offence."
    }

    illustration illustration_b {
        "( b ) [ Deleted by Act 51 of 2007 ]"
    }

    illustration illustration_c {
        "( c ) A , a surgeon, sees a child suffer an accident which is likely to prove fatal unless an operation is immediately performed. There is no time to apply to the child’s guardian. A performs the operation in spite of the entreaties of the child, intending, in good faith, the child’s benefit. A has committed no offence."
    }

    illustration illustration_d {
        "( d ) A is in a house which is on fire, with Z , a child. People below hold out a blanket. A drops the child from the house‑top, knowing it to be likely that the fall may kill the child, but not intending to kill the child, and intending in good faith, the child’s benefit. Here, even if the child is killed by the fall, A has committed no offence."
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr93-#pr93-

statute 93 "Communication made in good faith" effective 1872-01-01 {
    exception communication_made_in_good_faith {
        "No communication made in good faith is an offence by reason of any harm to the person to whom it is made, if it is made for the benefit of that person."
        "Not an offence by reason of that harm."
    }

    illustration illustration_a {
        "A , a surgeon, in good faith, communicates to a patient his opinion that he cannot live. The patient dies in consequence of the shock. A has committed no offence, though he knew it to be likely that the communication might cause the patient’s death."
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr94-#pr94-

statute 94 "Act to which a person is compelled by threats" effective 1872-01-01 {
    definitions {
        defence_rule := "Except murder and offences against the State punishable with death, nothing is an offence which is done by a person who is compelled to do it by threats, which, at the time of doing it, reasonably cause the apprehension that instant death to that person or any other person will otherwise be the consequence:";
    }

    elements {
        /// The defence applies only if the excluded offences are absent and every compulsion condition is satisfied.
        all_of {
            circumstance excluded_offences := "The act is not murder and is not an offence against the State punishable with death.";
            actus_reus act_done := "A person does the act.";
            circumstance compelled_by_threats := "The person is compelled to do the act by threats.";
            circumstance timing_of_threats := "At the time of doing the act, the threats reasonably cause the apprehension that instant death to that person or any other person will otherwise be the consequence.";
        }
    }

    exception compulsion_by_threats {
        "Except for murder and offences against the State punishable with death, a person is compelled to do the act by threats which, at the time of doing it, reasonably cause the apprehension that instant death to that person or any other person will otherwise be the consequence."
        "Nothing is an offence."
    }

    exception explanation_1 {
        "Explanation 1.—A person who, of his own accord, or by reason of a threat of being beaten, joins gang-robbers knowing their character, is not entitled to the benefit of this exception on the ground of his having been compelled by his associates to do anything that is an offence by law."
        priority 2
        defeats compulsion_by_threats
    }

    exception explanation_2 {
        "Explanation 2.—A person seized by gang-robbers, and forced by threat of instant death to do a thing which is an offence by law — for example, a smith compelled to take his tools and to force the door of a house for the gang‑robbers to enter and plunder it — is entitled to the benefit of this exception."
    }
}

/// @jurisdiction singapore
