statute 95 "Act causing slight harm" effective 1872-01-01 {
    definitions {
        slight_harm_rule := "Nothing is an offence by reason that it causes, or that it is intended to cause, or that it is known to be likely to cause, any harm, if that harm is so slight that no person of ordinary sense and temper would complain of such harm.";
        slight_harm := "Harm so slight that no person of ordinary sense and temper would complain of such harm.";
    }

    exception slight_harm {
        "Nothing is an offence by reason that it causes, or that it is intended to cause, or that it is known to be likely to cause, any harm, if that harm is so slight that no person of ordinary sense and temper would complain of such harm."
        "Nothing is an offence."
    }
}

