/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr97-#pr97-
/// @amendment [15/2019]

statute 97 "Right of private defence of the body and of property" effective 1872-01-01 effective 2020-01-01 {
    definitions {
        private_defence_body := "Every person has a right, subject to the restrictions contained in sections 98 and 106A, to defend his own body, and the body of any other person, against any offence affecting the human body.";
        private_defence_property := "Every person has a right, subject to the restrictions contained in sections 98 and 106A, to defend the property, whether movable or immovable, of himself or of any other person, against any act which is an offence falling under the definition of theft, robbery, mischief or criminal trespass, or which is an attempt to commit theft, robbery, mischief or criminal trespass.";
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr98-#pr98-
/// @amendment [15/2019]
statute 98 "Extent to which right may be exercised" effective 1872-01-01 effective 2020-01-01 {
    subsection (1) {
        definitions {
            private_defence_proportionality_limit := "The right of private defence does not extend to the inflicting of more harm than it is reasonably necessary in the circumstances. [15/2019]";
        }
    }

    subsection (2) {
        definitions {
            no_private_defence_where_public_authority_available := "There is no right of private defence in cases in which there is reasonable opportunity to have recourse to the protection of a public authority in the circumstances. [15/2019]";
        }
    }

    illustration illustration_a {
        "( a ) Z ambushes A in a secluded area and attempts to kill A . A kills Z while fending off Z ’s attack. A is guilty of no offence because, in the circumstances, A had no reasonable opportunity to have recourse to the protection of a public authority."
    }

    illustration illustration_b {
        "( b ) Z ambushes A in a secluded area and attempts to kill A . A ’s right of private defence arises because, at that point of time, A had no reasonable opportunity to have recourse to the protection of a public authority. In the midst of the struggle between A and Z , a police patrol car arrives on the scene. A ’s right of private defence ceases the moment A had reasonable opportunity to have recourse to the protection of the police."
    }
}

/// @jurisdiction singapore
/// @meta act=Penal Code 1871
/// @meta source=https://sso.agc.gov.sg/Act/PC1871?ProvIds=pr99-#pr99-
/// @amendment [15/2019]

statute 99 "Right of private defence against act of person of unsound mind, etc." effective 1872-01-01 effective 2020-01-01 {
    definitions {
        private_defence_against_act_not_offence_due_to_actor_status := "When an act, which would otherwise be a certain offence, is not that offence, by reason of the youth, the want of maturity of understanding, the unsoundness of mind, or the intoxication of the person doing that act, or by reason of any misconception on the part of that person, every person has the same right of private defence against that act which he would have if the act were that offence. [15/2019]";
    }

    illustration illustration_a {
        "( a ) Z , under the influence of madness, attempts to kill A . Z is guilty of no offence. But A has the same right of private defence which he would have if Z were sane."
    }

    illustration illustration_b {
        "( b ) A enters, by night, a house which he is legally entitled to enter. Z , in good faith, taking A for a housebreaker, attacks A . Here Z , by attacking A under this misconception, commits no offence. But A has the same right of private defence against Z , which he would have if Z were not acting under that misconception."
    }
}
